local function validate_token()
    local auth_header = ngx.var.http_authorization
    if not auth_header then
        return nil, "Missing authorization header"
    end
    
    local token = string.match(auth_header, "Bearer%s+(.+)")
    if not token then
        return nil, "Invalid authorization format"
    end
    
    -- Simulate token validation (replace with actual JWT validation or DB lookup)
    local decoded_token = ngx.decode_base64(token)
    if not decoded_token then
        return nil, "Invalid token encoding"
    end
    
    local user_data = cjson.decode(decoded_token)
    if not user_data or not user_data.user_id or not user_data.role then
        return nil, "Invalid token data"
    end
    
    return user_data.user_id, user_data.role
end

local function check_permission(required_role)
    local user_id, user_role = validate_token()
    if not user_id then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return
    end
    
    local roles = {
        ["admin"] = 3,
        ["editor"] = 2,
        ["user"] = 1
    }
    
    if not roles[user_role] or not roles[required_role] then
        ngx.status = 403
        ngx.say('Forbidden')
        ngx.exit(403)
        return
    end
    
    if roles[user_role] < roles[required_role] then
        ngx.status = 403
        ngx.say('Forbidden')
        ngx.exit(403)
        return
    end
end

local function should_skip_check()
    local uri = ngx.var.uri
    if string.find(uri, "/admin") or string.find(uri, "/api") then
        return true
    end
    return false
end

if should_skip_check() then
    return
end

local uri = ngx.var.uri
if string.find(uri, "/admin/users") then
